1	const forwardDelta: Record<string, { dx: number; dy: number }> = {
2	  N: { dx: 0, dy: 1 },
3	  E: { dx: 1, dy: 0 },
4	  S: { dx: 0, dy: -1 },
5	};
6	
7	export function moveRover(rover: { x: number; y: number; heading: string }, commands: string) {
8	  if (commands === "F") {
9	    const delta = forwardDelta[rover.heading];
10	    if (delta) return { ...rover, x: rover.x + delta.dx, y: rover.y + delta.dy };
11	  }
12	  return rover;
13	}
